css:
.wrapper-exec-navdrill{--surface:var(--block-bg-color,#15151A);--surface-raised:#1B1B22;--ink:var(--color-text,#F4F4F7);--ink-soft:var(--color-gray-700,#C2C2CC);--muted:var(--color-gray-500,#8A8A96);--line:var(--color-gray-200,#26262B);--accent:var(--color-primary,#FFD21E);--accent-2:var(--color-secondary,#FF3D8B);container-type:inline-size;height:100%;box-sizing:border-box;overflow:auto;color:var(--ink);font-family:var(--font-stack-primary,'Inter',system-ui,-apple-system,'Segoe UI',Roboto,sans-serif);font-variant-numeric:tabular-nums;}
.wrapper-exec-navdrill .exnd-head{margin:0 0 16px;}
.wrapper-exec-navdrill .exnd-eyebrow{display:inline-flex;align-items:center;gap:7px;font:700 11px/1.2 var(--font-stack-primary,'Inter',system-ui);letter-spacing:.14em;text-transform:uppercase;color:var(--ink-soft);}
.wrapper-exec-navdrill .exnd-eyebrow::before{content:"";width:7px;height:7px;border-radius:50%;background:var(--accent);}
.wrapper-exec-navdrill .exnd-heading{margin:8px 0 0;font:800 22px/1.15 var(--font-stack-primary,'Inter',system-ui);letter-spacing:-.01em;color:var(--ink);}
.wrapper-exec-navdrill .exnd-lede{margin:4px 0 0;max-width:62ch;font:500 13px/1.5 var(--font-stack-primary,'Inter',system-ui);color:var(--muted);}
.wrapper-exec-navdrill .exnd-rule{display:block;height:2px;width:64px;margin-top:12px;border-radius:2px;background:linear-gradient(90deg,var(--accent),var(--accent-2));}
.wrapper-exec-navdrill .exnd-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:14px;}
.wrapper-exec-navdrill .exnd-card{display:flex;flex-direction:column;gap:6px;min-width:0;min-height:44px;box-sizing:border-box;text-decoration:none;background:var(--surface);border:1px solid var(--line);border-left:3px solid var(--accent);border-radius:14px;padding:16px 18px;color:var(--ink);box-shadow:0 1px 0 rgba(255,255,255,.03) inset,0 6px 18px rgba(0,0,0,.5);transition:transform .15s ease,box-shadow .15s ease,border-color .15s ease,background .15s ease;}
.wrapper-exec-navdrill .exnd-card:hover{transform:translateY(-2px);background:var(--surface-raised);border-color:color-mix(in srgb,var(--accent) 35%,var(--line));border-left-color:var(--accent);box-shadow:0 0 24px -8px color-mix(in srgb,var(--accent) 55%,transparent),0 10px 26px rgba(0,0,0,.55);}
.wrapper-exec-navdrill .exnd-card:active{transform:translateY(0);}
.wrapper-exec-navdrill .exnd-card:focus-visible{outline:2px solid var(--accent);outline-offset:2px;}
.wrapper-exec-navdrill .exnd-ico{display:inline-flex;align-items:center;justify-content:center;width:40px;height:40px;border-radius:10px;background:color-mix(in srgb,var(--accent) 14%,transparent);color:var(--accent);font-size:18px;margin-bottom:2px;}
.wrapper-exec-navdrill .exnd-title{font-size:15px;font-weight:800;letter-spacing:-.01em;color:var(--ink);overflow-wrap:break-word;}
.wrapper-exec-navdrill .exnd-desc{font-size:12.5px;font-weight:500;line-height:1.45;color:var(--muted);overflow-wrap:break-word;}
.wrapper-exec-navdrill .exnd-go{margin-top:auto;padding-top:8px;font-size:12px;font-weight:700;color:var(--accent);display:inline-flex;align-items:center;gap:6px;}
.wrapper-exec-navdrill .exnd-arr{transition:transform .15s ease;}
.wrapper-exec-navdrill .exnd-card:hover .exnd-arr{transform:translateX(3px);}
@container (max-width:1080px){.wrapper-exec-navdrill .exnd-grid{grid-template-columns:repeat(3,minmax(0,1fr));}}
@container (max-width:720px){.wrapper-exec-navdrill .exnd-grid{grid-template-columns:repeat(2,minmax(0,1fr));}}
@container (max-width:460px){.wrapper-exec-navdrill .exnd-grid{grid-template-columns:1fr;}}
@media (prefers-reduced-motion:reduce){.wrapper-exec-navdrill .exnd-card,.wrapper-exec-navdrill .exnd-arr{transition:none;}.wrapper-exec-navdrill .exnd-card:hover{transform:none;}.wrapper-exec-navdrill .exnd-card:hover .exnd-arr{transform:none;}}
